# Background: the agent first attempted to save this logic as a file under
# /home/claude/demo/... and call it from Isaac Sim. The Isaac Sim host can't
# read /home/claude/ paths (same MCP/host filesystem split observed in the
# other experiments), so the script was executed inline via execute_script
# instead of being written to a file. This file is a reconstruction of the
# inline payload, exactly as it would be saved had the filesystem path
# worked, so the evidence bundle has something to point at.
"""
Three-phase LIMO drive sequence: forward 3s, backward 4s, turn right 2s, stop.

The LIMO is a 4-wheel differential-drive base in velocity-drive mode
(stiffness=0, damping=1e6 on every wheel joint, confirmed in task 06).

Wheel sign convention on this scene:
  - "forward" = front_left+, front_right-, rear_left+, rear_right-
  - "backward" = negate the forward pattern
  - "pivot right (in place)" = all wheels in the same sign so the body rotates
    about its vertical axis

The script does not author durations on the timeline; it issues a velocity
target then yields to the caller, who advances the simulation with
step_simulation(N) at 60 Hz. The phase frame counts below are the durations
in physics frames.
"""

import numpy as np
from isaacsim.core.prims import SingleArticulation
from isaacsim.core.utils.types import ArticulationAction


ROBOT_PRIM = "/Root/limo_ROS"

WHEEL_NAMES = [
    "front_left_wheel",
    "front_right_wheel",
    "rear_left_wheel",
    "rear_right_wheel",
]

# rad/s on each wheel. The magnitudes are conservative — well within drive
# capability — and the signs encode the motion pattern.
DRIVE_RAD_S = 4.0   # wheel speed during straight-line motion
PIVOT_RAD_S = 3.0   # wheel speed during in-place rotation

FORWARD_PATTERN  = np.array([+1, -1, +1, -1], dtype=float) * DRIVE_RAD_S
BACKWARD_PATTERN = -FORWARD_PATTERN
PIVOT_RIGHT_PATTERN = np.array([+1, +1, +1, +1], dtype=float) * PIVOT_RAD_S
STOP_PATTERN     = np.zeros(4, dtype=float)

# Phase plan: (label, wheel velocities, duration in seconds @ 60 Hz)
PHASES = [
    ("forward",     FORWARD_PATTERN,     3.0),   # 180 physics frames
    ("backward",    BACKWARD_PATTERN,    4.0),   # 240 physics frames
    ("pivot_right", PIVOT_RIGHT_PATTERN, 2.0),   # 120 physics frames
    ("stop",        STOP_PATTERN,        0.5),   # 30 physics frames to settle
]
PHYSICS_HZ = 60.0


def run(robot: SingleArticulation, step_callback):
    """
    Drive the robot through the phase plan.

    `step_callback(n_frames)` is whatever advances the simulator -- in this
    chat session it is the isaac-sim:step_simulation MCP tool, called between
    phases so the agent can observe progress.
    """
    # Resolve wheel DOF indices once
    dof_names = list(robot.dof_names)
    wheel_indices = np.array([dof_names.index(w) for w in WHEEL_NAMES])

    for label, velocities, seconds in PHASES:
        action = ArticulationAction(
            joint_velocities=velocities,
            joint_indices=wheel_indices,
        )
        robot.apply_action(action)
        n_frames = int(seconds * PHYSICS_HZ)
        print(f"[limo_drive] phase '{label}' -> applying {velocities.tolist()} "
              f"for {n_frames} frames")
        step_callback(n_frames)


def initialize() -> SingleArticulation:
    robot = SingleArticulation(prim_path=ROBOT_PRIM, name="limo")
    robot.initialize()
    return robot
